var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 10월 28일. 평행 세계 런던, <color=#ffd34c>황금 새벽회</color> 지하 사원\\n<color=#ffd34c>심야</color>","JPN":"1888年10月28日。パラレルワールドのロンドン、<color=#ffd34c>黄金の暁団</color>地下寺院\\n<color=#ffd34c>深夜</color>","ENG":"[[","TWN":"1888年10月28日。平行世界倫敦，<color=#ffd34c>黃金黎明會</color>地下寺廟\\n<color=#ffd34c>深夜</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"모든 이야기를 처음으로 되돌린다고?","JPN":"全ての物語を振り出しに戻すって？","ENG":"Revert all the stories to their beginning?","TWN":"要把所有故事都回到起點嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼, 정말로 멸망해 버린 세계를 되돌리는 게 가능하단 말이야……?","JPN":"じゃあ、本当に滅亡した世界を元に戻すことが可能なの……？","ENG":"You mean it's actually possible to bring back a world that was completely destroyed...?","TWN":"真的有可能讓已經毀滅的世界恢復原狀嗎？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그건 무모한 이야기야, 아이린!","JPN":"それは無謀な話だ、アイリーン！","ENG":"That's madness, Irene!","TWN":"那是個魯莽的事，愛琳！"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마가 저질렀던 천사 강림 의식은 그저 엉터리 의식에 불과해!","JPN":"深夜の殺人鬼が行った天使降臨の儀式は、ただのデタラメに過ぎない！","ENG":"The angel summoning ritual committed by the Midnight Killer was just a farce!","TWN":"午夜殺人魔所進行的天使降臨儀式不過是個荒唐的儀式而已！"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하물며 천사라는 것이 존재한다고 해도, 정말 자네가 원하는 것을 이루어 줄 수 있을까?","JPN":"仮に天使というものが存在したとして、それが本当に君の望みを叶えられるのかね？","ENG":"Even if angels were real, would they really give you what you want?","TWN":"即便天使真的存在，真的能實現你的願望嗎？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"다시 한번 생각해 보게……!","JPN":"もう一度考えてみたまえ……！","ENG":"Please reconsider...!","TWN":"再好好考慮一下吧！"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 세피라라는 힘이 정확히 어떤 식으로 현실에 작용하는지는 모르겠지만…….","JPN":"そのセフィラという力が、具体的にどういう風に現実に作用するのかは知らないが……","ENG":"I don't know exactly how the power of Sephira affects reality...","TWN":"雖然不知道那叫做生命樹的力量究竟是如何作於于現實的……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네는 자네의 기억을 재구성하는 우회적인 방법으로 세계를 되돌려 놓을 수 있었어.","JPN":"君は、君の記憶を再構成するという遠回りなやり方で世界を元に戻すことに成功した。","ENG":"But you've used it to reconstruct your memories and rewind the world indirectly.","TWN":"你通過重構自己的記憶，以一種迂回的方式將世界恢復了原狀。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아마도 그건 망각의 여신으로부터 미움받는 자네이기에 떠올릴 수 있는 발상이었겠지.","JPN":"おそらくそれは、忘却の女神に愛されなかった君だからこそできた発想だったのだろう。","ENG":"Maybe that's something only you, hated by the goddess of oblivion, could've come up with.","TWN":"也許那是因為你是被遺忘女神所詛咒的人，才能想到這樣的主意吧。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그렇다고 해도 기억의 당사자인 자네 자신은 과거로 돌아갈 수 없었어.","JPN":"しかし、記憶の当事者である君自身が過去に戻れたわけではなかった。","ENG":"But even so, you yourself couldn't return to the past.","TWN":"但即便如此，作為記憶的主人的你自己也沒能回到過去。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 증거로 이 세계에는 자네가 두 사람 존재하게 되지 않았나?","JPN":"その証拠として、この世界には君が2人存在しているだろう？","ENG":"If you could, why are there two of you in this world?","TWN":"這個世界上還有兩個你存在，這就是證據不是嗎？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러고 보니…….","JPN":"言われてみれば……","ENG":"Now that you mention it...","TWN":"這麼說來……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인…….","JPN":"アバーライン……","ENG":"Abberline...","TWN":"艾伯林……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 재밌군요.","JPN":"ふふ、面白いですね。","ENG":"Haha, how amusing.","TWN":"呵呵，真有趣啊。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래서 그게 뭐 어쨌다는 거죠?","JPN":"それで？　それがどうしたと言うのですか？","ENG":"And what of it?","TWN":"所以那又怎麼樣呢？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"기억을 초월하여, 모든 이야기를 처음으로 되돌리겠다고?","JPN":"記憶を超越して、全ての物語を振り出しに戻すと言ったね？","ENG":"You want to transcend memory and revert all the stories to their beginning?","TWN":"你想超越記憶，要將整個故事回到起點嗎？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"세계를 되돌리더라도, 자네가 지금껏 저질러 왔던 죄는 사라지지 않아.","JPN":"世界を元に戻したところで、君が今まで犯してきた罪が消えるわけではない。","ENG":"Even if you rewind the world, the sins you've committed won't just vanish.","TWN":"即使世界恢復正常，你至今所犯下的罪行也不會消失。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하물며 성공한다고 하더라도, 자네는 지금처럼 어떤 세계에도 속하지 못하게 되겠지.","JPN":"それに成功したとしても、君は今のようにどの世界にも属せなくなるだろう。","ENG":"Even if you succeed, you'll no longer belong to any world.","TWN":"即便成功了，你也將像現在一樣，不屬於任何一個世界。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"결국, 자네는 자네가 만들어낸 세계에서도 외톨이로 남게 될 거야.","JPN":"結局、君は君自身が作り出した世界でも一人ぼっちになるんだ。","ENG":"In the end, even in the world you create, you'll be all alone.","TWN":"最終，你在自己創造的世界中也會成為孤獨者。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"누구에게도 이해받지 못한 채, 누구와도 인연을 맺지 못한 채, 미지의 존재로 남을 거라고!","JPN":"誰からも理解されず、誰かと縁を結ぶこともできず、未知の存在としてただ残されるだけだ！","ENG":"No one will understand you. No one will be connected to you. You'll remain as an unknown to everyone!","TWN":"沒有人理解你，也沒有人與你結緣，你將永遠是個未知的存在！"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아이린, 자네가 바라는 세계가 진정 그런 세계인가……?","JPN":"アイリーン、君が望む世界とは、真にそのような世界なのかね……？","ENG":"Is that truly the kind of world you want, Irene...?","TWN":"愛琳，你所期望的世界真的是那樣的世界嗎？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"정녕, 영원히 고독한 존재로 남길 바라는 건가……!","JPN":"本当に、永遠の時を孤独な存在として残ってもいいと言うのか……！","ENG":"Do you really want to remain a lonely existence forever...?!","TWN":"真的希望永遠成為孤獨的存在嗎？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후…….","JPN":"ふふ……","ENG":"Haha...","TWN":"呵呵……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"겉모습은 그럴싸하게 만들어 졌지만, 결국에는 내 기억 속 미련일 뿐인가…….","JPN":"見た目はそれっぽくても、所詮は私の記憶の中の未練でしかないわけね……","ENG":"I suppose this was all just lingering regret in my memory...","TWN":"外表看似一樣，但最終不過是我記憶中的執念而已……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"고독한 존재라고요? 얼마든지요, 애버라인.","JPN":"孤独な存在ですか？　望むところです、アバーライン。","ENG":"A lonely existence? I welcome it, Abberline.","TWN":"孤獨的存在嗎？當然了，艾伯林。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"애초부터 당신을 떠나보낸 뒤로 저는 줄곧 외톨이였답니다.","JPN":"そもそもあなたに先立たれて以来、私はずっと一人ぼっちでした。","ENG":"Ever since I let you go, I've been alone anyway.","TWN":"自從你離開後，我一直都是孤身一人。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신과 이 세계를 되돌리기 위해서라면, 저는 얼마든지 외톨이로 남을 수 있어요.","JPN":"あなたとこの世界を取り戻すためなら、私はいくらでも一人になりましょう。","ENG":"If it means bringing you and this world back, I'll gladly stay that way.","TWN":"只要你和這個世界能後重回過去，我可以一直孤獨下去。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그게 무슨……?","JPN":"それはどういう……？","ENG":"What are you talking about...?","TWN":"那是什麼？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 이렇게 먼발치에서 당신을 지켜보는 것으로도 충분해요.","JPN":"私はこうして、ただ遠くからあなたを見守るだけで十分です。","ENG":"Just watching you from afar is enough for me.","TWN":"我能在遠處這樣看著你就足夠了。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신만큼은 언제 어디서나 아름답고 우아한 백조로 남길 바라니까요.","JPN":"あなただけは、いつまでも美しく優雅な白鳥でいて欲しいから。","ENG":"I want you to always remain a beautiful, graceful swan, no matter where you are.","TWN":"我希望無論何時何地，你都能像優雅的天鵝一樣美麗。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어차피 이제 와서 당신의 손을 잡기에는, 제 손이 너무나 더러워져 버렸으니까요.","JPN":"どのみち、今更あなたの手を取るには、私の手は汚れきってしまった。","ENG":"Besides, my hands are far too tainted now to ever hold yours again.","TWN":"我的手已經太髒了，已經不配再與你攜手了。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L4_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은 늘 수수께끼 풀이가 업이라고 했죠?","JPN":"あなたはいつも謎解きが仕事だと言いましたよね？","ENG":"You always said solving riddles was your profession, didn't you?","TWN":"你總是說解謎是你的工作，對吧？"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇다면 다시 만날 그 세계에서는 제가 당신의 수수께끼, 그 자체가 되어드리죠.","JPN":"でしたらまた会うその世界では、私があなたの謎そのものになってさしあげましょう。","ENG":"Then in the world we meet again, I'll be your greatest mystery.","TWN":"那麼在我們再次相遇的那個世界裡，我將成為你的謎題本身。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"언젠가 당신과 만났던 미지의 존재, 존 스미스처럼.","JPN":"かつてあなたと出会った未知なる存在、ジョン・スミスのように。","ENG":"Just like John Smith, the unknown figure you once met...","TWN":"就如同某天與你相遇的未知存在約翰·史密斯一樣。"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"L50_1","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"L50_1","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"L50_1","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"L50_1","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};